                # Search for element with matching ID attribute
                referenced_elements = self.xml_doc.xpath(
                    f'//*[@ID="{ref_id}"]'
                )
                if not referenced_elements:
                    raise ValueError(
                        f"Referenced element with ID '{ref_id}' not found"
                    )
