        # Get inclusive namespaces for SignedInfo canonicalization
        c14n_inclusive_ns = None
        if c14n_method is not None:
            inc_ns_elem = c14n_method.find(
                "ec:InclusiveNamespaces", namespaces=NAMESPACES
            )
